import newObject from '../utils/newObject'

function AppContainer() {
    return (
        <div className="app-container">
            <header className="header">
                <h1>🎵 Sound Landscape</h1>
            </header>
            <div className="main">
                <aside className="sidebar">
                    <button onClick={newObject}>Добавить объект</button>
                </aside>
                <div
                    className="canvas-container"
                    ref={canvasRef}
                    onMouseMove={(e) => objectDragging(e)}
                    onMouseUp={(e) => stoppedDragging(e)}
                    style={{
                        position: 'relative',
                    }}
                >
                    {objects.map((obj) => (
                        <div
                            onMouseDown={(e) => mouseDownOnObject(obj.id)}
                            className="obj"
                            key={obj.id}
                            style={{
                                position: 'absolute',
                                left: obj.left,
                                top: obj.top,
                            }}
                        ></div>
                    ))}
                </div>
            </div>
        </div>
    );
}
